const kYCListTransitionsByCase = `-- name: KYCListTransitionsByCase :many
SELECT id, case_id, from_status, to_status, actor_user_id, reason, metadata, created_at
FROM kyc_case_transitions
WHERE case_id = $1
ORDER BY created_at ASC, id ASC
`

func (q *Queries) KYCListTransitionsByCase(ctx context.Context, caseID string) ([]KycCaseTransition, error) {
	rows, err := q.db.Query(ctx, kYCListTransitionsByCase, caseID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []KycCaseTransition{}
	for rows.Next() {
		var i KycCaseTransition
		if err := rows.Scan(
			&i.ID,
			&i.CaseID,
			&i.FromStatus,
			&i.ToStatus,
			&i.ActorUserID,
			&i.Reason,
			&i.Metadata,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

